THOUGHT: The script file was created in the wrong directory. Let's create it in the current directory and run it.

```bash
cd /llvm-autofix-deps/llvm/llvm/llvm/test/Transforms/InstCombine && cat > update_fabs_test.py << 'EOF'
import sys
import re

with open('fabs.ll', 'r') as f:
    lines = f.readlines()

i = 0
while i < len(lines):
    if lines[i].strip().startswith('define'):
        func_start = i
        # Find the end of function
        for j in range(i, len(lines)):
            if lines[j].strip() == '}':
                func_end = j
                break
        # Check if function body contains nnan (excluding comments)
        has_nnan = False
        for j in range(func_start, func_end+1):
            line = lines[j]
            if not line.strip().startswith(';') and 'nnan' in line:
                has_nnan = True
                break
        if has_nnan:
            # Find CHECK-LABEL for this function
            for k in range(func_start, -1, -1):
                if lines[k].strip().startswith('; CHECK-LABEL:'):
                    # Find all CHECK-NEXT lines until next CHECK-LABEL or end of function
                    for l in range(k+1, len(lines)):
                        if lines[l].strip().startswith('; CHECK-LABEL:') or lines[l].strip().startswith('define'):
                            break
                        if '@llvm.fabs' in lines[l] and 'call' in lines[l]:
                            if 'nnan' not in lines[l]:
                                lines[l] = lines[l].replace('= call ', '= call nnan ')
                    break
        i = func_end + 1
    else:
        i += 1

with open('fabs.ll', 'w') as f:
    f.writelines(lines)
print('Updated test file')
EOF
python3 update_fabs_test.py
```

